    $x = [xml]$xml
    $props = $x.INSTANCE.PROPERTY
    $nameP = ($props | Where-Object { $_.NAME -eq 'Name' }).VALUE
    $dataP = ($props | Where-Object { $_.NAME -eq 'Data' }).VALUE
